// Triangle bottom edge
const tri = {
    x: 200, y: 200,
    vertices: [
        {x: 200, y: 180},  // apex
        {x: 180, y: 220},  // bottom-left
        {x: 220, y: 220}   // bottom-right
    ]
};
// Bottom edge is vertices[1]→vertices[2]: \(180,220\)→\(220,220\), dir = \(40, 0\)
// This goes LEFT to RIGHT

// Square top edge
const sq = {
    x: 200, y: 248,
    vertices: [
        {x: 180, y: 228},
        {x: 220, y: 228},
        {x: 220, y: 268},
        {x: 180, y: 268}
    ]
};
// Top edge is vertices[0]→vertices[1]: \(180,228\)→\(220,228\), dir = \(40, 0\)
// This ALSO goes LEFT to RIGHT

// Both edges go in the SAME direction \(40, 0\)
// For flush contact, edges should be ANTI-parallel \(opposite directions\)
// But these go the same way because triangle is CCW and square is CW

// The outward normals:
// Triangle bottom edge \(CCW\): outward normal points DOWN \(away from center at y=200\)
// Square top edge \(CW\): outward normal points UP \(away from center at y=248\)
// DOWN and UP = anti-parallel normals ✓ \(normalDot ≈ -1\)

// Edge directions are PARALLEL \(same direction\), not anti-parallel
// The rotation formula: rotDelta = \(angleB + PI\) - angleA
// angleA = atan2\(0, 40\) = 0
// angleB = atan2\(0, 40\) = 0
// rotDelta = \(0 + PI\) - 0 = PI = 180°
// This means: rotate dragged square 180° to make its edge anti-parallel to triangle's edge
// But for a square, 180° rotation produces the same shape!

console.log\('Triangle bottom: \(180,220\) -> \(220,220\), dir: right'\);
console.log\('Square top: \(180,228\) -> \(220,228\), dir: right'\);
console.log\('Edges are parallel \(same direction\), outward normals are anti-parallel'\);
console.log\('rotDelta = 180° \(correct, makes edges anti-parallel\)'\);
console.log\('For a square, 180° rotation = same visual result'\);
")

