console.log\('Hex edges:'\);
for \(let i = 0; i < 6; i++\) {
    const e = hexEdges[i];
    console.log\('  Edge', i, ': \(', e.start.x.toFixed\(1\), e.start.y.toFixed\(1\), '\) -> \(', e.end.x.toFixed\(1\), e.end.y.toFixed\(1\), '\)'\);
}

