console.log\('Square top edge: \(', sqEdges[0].start.x, sqEdges[0].start.y, '\) -> \(', sqEdges[0].end.x, sqEdges[0].end.y, '\)'\);

const match = MirrorEdgeSnapping.findBestMatch\(sq, [hex]\);
console.log\('Match:', match\);
