import { MirrorEdgeSnapping } from './js/systems/MirrorEdgeSnapping.js';

const rt = {
    x: 200, y: 200,
    vertices: [{x: 180, y: 220}, {x: 220, y: 220}, {x: 180, y: 180}]
};
const edges = MirrorEdgeSnapping.getEdges\(rt\);
for \(let i = 0; i < 3; i++\) {
    const n = MirrorEdgeSnapping.outwardNormal\(edges[i]\);
    const mid = MirrorEdgeSnapping.midpoint\(edges[i]\);
    const toCenter = { x: rt.x - mid.x, y: rt.y - mid.y };
    const dot = n.x * toCenter.x + n.y * toCenter.y;
    console.log\('Edge', i, 'normal:', n.x.toFixed\(3\), n.y.toFixed\(3\), 'dot:', dot.toFixed\(3\)\);
}
// Edge 1 \(hypotenuse\) should point upper-right \(away from right angle at bottom-left\)
" 2>&1)

